from openai_agents import AgentRunner, trace

def detect_token_bloat(callback):
    @trace(callback=callback)
    def monitor_agent_latency(runner: AgentRunner):
        stats = runner.get_run_stats()
        if stats.total_tokens > 8000:
            return {
                'issue': 'TOKEN_BLOAT',
                'tokens': stats.total_tokens,
                'agents': len(stats.agent_handoffs),
                'latency_ms': stats.total_duration_ms
            }
        return None
    return monitor_agent_latency

from openai_agents import Agent, Runner
from time import perf_counter

def profile_handoffs(agents: list[Agent]):
    runner = Runner(agents)
    handoff_times = []

    def latency_hook(event):
        if event.type == 'agent_handoff':
            start = perf_counter()
            event.context['handoff_start'] = start
        elif event.type == 'agent_complete' and 'handoff_start' in event.context:
            duration = (perf_counter() - event.context['handoff_start']) * 1000
            if duration > 5000:
                handoff_times.append({
                    'from': event.prev_agent,
                    'to': event.agent,
                    'latency_ms': duration
                })

    runner.run(callback=latency_hook)
    return handoff_times

import tiktoken
from openai_agents import Agent

def analyze_prompt_tokens(agents: list[Agent]):
    encoding = tiktoken.get_encoding('cl100k_base')
    issues = []

    for agent in agents:
        sys_tokens = len(encoding.encode(agent.system_prompt))
        if sys_tokens > 2000:
            issues.append({
                'agent': agent.name,
                'sys_tokens': sys_tokens,
                'prompt': agent.system_prompt[:100] + '...',
                'recommendation': 'Reduce system prompt by 50%'
            })
    return issues
